sql:
SELECT COUNT(region_name) AS total_regions
FROM regions
ORDER BY region_name DESC;

SELECT COUNT(*) AS location_count
FROM locations
WHERE region_id = 1;

SELECT location_id, AVG(gold) AS average_gold, AVG(points) AS average_points
FROM gameplay_metrics
GROUP BY location_id;

SELECT locations.location_name, regions.region_name
FROM locations
JOIN regions ON locations.region_id = regions.region_id;

external_knowledge:
- "primary area" refers to the region with region_id = 1;
- "starting funds" is the minimum gold required to hunt in a location;
- "sites" refer to the different location types found in the data.

- 'Verdant realms' refer to regions with forests; 
- 'Hidden hunting grounds' are the locations classified as 'forest';
- 'Treasure' and 'gold' are synonymous; 
- 'Footholds of the gold-rich threshold' refer to the minimum gold required to hunt, which is greater than 50;
- 'Emerald domains' are another metaphor for the regions containing the specified locations;
- 'Modest sum' refers to the minimum gold greater than 50.

sql:
SELECT DISTINCT user_id
FROM player_progress
WHERE title = 'Novice';

SELECT location_id, visits, hunts
FROM location_metrics
WHERE visits > 100;
